  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});


const variant = {
  primary: ' bg-primary-500',
  success: ' bg-success-500',
  info: ' bg-info-500',
  warning: 'bg-warning-500',
  error: ' bg-error-500',
}

const bgColor = computed(() => {
  return variant[props.color]
})
</script>

