        <span class="h-6 select-none">
          <slot name="label" :timeline="timeline" />
        </span>
        <span class="h-full flex items-center select-none">
          <slot
            v-if="i < timelines.length - 1"
            name="prefix"
            :timeline="timeline"
          />
        </span>
      </div>

      <div v-if="timeline" class="col-span-9 flex">
        <div class="w-auto flex flex-col justify-start items-center">
          <span
          :class="bgColor"
            class="flex items-center justify-center h-6 w-6  rounded-full text-white text-xs select-none"
